#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[205];
    if (!fgets(s, sizeof(s), stdin)) return 0;

    int count = 0;
    for (int i = 0; s[i] != '\0'; i++) {
        char c = (char)tolower((unsigned char)s[i]);
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[205];
    if (!fgets(s, sizeof(s), stdin)) return 0;

    size_t n = strlen(s);
    if (n > 0 && s[n - 1] == '\n') s[n - 1] = '\0';

    for (size_t i = 0; s[i] != '\0'; ) {
        if (s[i] == ' ') {
            putchar(' ');
            i++;
        } else {
            size_t start = i;
            while (s[i] != '\0' && s[i] != ' ') i++;
            for (size_t j = i; j > start; j--) {
                putchar(s[j - 1]);
            }
        }
    }
    putchar('\n');
    return 0;
}

