#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[205];
    if (!fgets(s, sizeof(s), stdin)) return 0;

    size_t n = strlen(s);
    if (n > 0 && s[n - 1] == '\n') s[n - 1] = '\0';

    char t[205];
    int m = 0;
    for (size_t i = 0; s[i] != '\0'; i++) {
        if (isalpha((unsigned char)s[i])) {
            t[m++] = (char)tolower((unsigned char)s[i]);
        }
    }

    int ok = 1;
    for (int i = 0, j = m - 1; i < j; i++, j--) {
        if (t[i] != t[j]) {
            ok = 0;
            break;
        }
    }

    printf("%s\n", ok ? "YES" : "NO");
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int is_vowel(char c) {
    c = (char)tolower((unsigned char)c);
    return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
}

int main(void) {
    char s[205];
    if (!fgets(s, sizeof(s), stdin)) return 0;

    size_t n = strlen(s);
    if (n > 0 && s[n - 1] == '\n') s[n - 1] = '\0';

    int count = 0;
    for (size_t i = 0; s[i] != '\0'; ) {
        while (s[i] == ' ') i++;
        if (s[i] == '\0') break;

        size_t start = i;
        while (s[i] != '\0' && s[i] != ' ') i++;
        size_t end = i - 1;

        if (is_vowel(s[start]) && is_vowel(s[end])) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}

