}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    int k;
    if (scanf("%d", &k) != 1) return 0;
    int ch;
    while ((ch = getchar()) != '\n' && ch != EOF) {}

    char s[205];
    if (!fgets(s, sizeof(s), stdin)) s[0] = '\0';

    size_t n = strlen(s);
    if (n > 0 && s[n - 1] == '\n') s[n - 1] = '\0';

    k %= 26;
    for (size_t i = 0; s[i] != '\0'; i++) {
        if (isupper((unsigned char)s[i])) {
            s[i] = (char)('A' + (s[i] - 'A' + k) % 26);
        } else if (islower((unsigned char)s[i])) {
            s[i] = (char)('a' + (s[i] - 'a' + k) % 26);
        }
    }

    printf("%s\n", s);
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[205];
    if (!fgets(s, sizeof(s), stdin)) return 0;

    size_t n = strlen(s);
    if (n > 0 && s[n - 1] == '\n') s[n - 1] = '\0';

    int best_len = 0;
    int best_start = -1;

    for (size_t i = 0; s[i] != '\0'; ) {
        while (s[i] == ' ') i++;
        if (s[i] == '\0') break;

        size_t start = i;
        while (s[i] != '\0' && s[i] != ' ') i++;
        int len = (int)(i - start);

        if (len > best_len) {
            best_len = len;
            best_start = (int)start;
        }
    }

    if (best_start == -1) {
        printf("NONE\n");
    } else {
        for (int i = best_start; i < best_start + best_len; i++) {
            putchar(s[i]);
        }
        putchar('\n');
    }

    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char text[205], pat[205];

    if (!fgets(text, sizeof(text), stdin)) return 0;
    if (!fgets(pat, sizeof(pat), stdin)) return 0;

    size_t nt = strlen(text), np = strlen(pat);
    if (nt > 0 && text[nt - 1] == '\n') text[--nt] = '\0';
    if (np > 0 && pat[np - 1] == '\n') pat[--np] = '\0';

    int count = 0;
    if (np == 0 || np > nt) {
        printf("0\n");
        return 0;
    }

    for (size_t i = 0; i + np <= nt; i++) {
        if (strncmp(&text[i], pat, np) == 0) {
            count++;
        }
    }

    printf("%d\n", count);
    return 0;
}
